                  final filterParams =
                      ref.watch(sessionFilterParametersNotifierProvider);
                  final isFilterActive = filterParams.keyword != null ||
                      filterParams.player != null ||
                      filterParams.startDate != null ||
                      filterParams.endDate != null ||
                      (filterParams.location != null &&
                          filterParams.location!.isNotEmpty);

                  return LayoutBuilder(
                    builder: (context, constraints) {
                      return SingleChildScrollView(
                        physics: const AlwaysScrollableScrollPhysics(),
                        child: Column(
                          children: [
                            if (context.isLandscape) const Gap(16),
                            SessionSearchBarWithFilter(
                              word: filterParams.keyword ?? '',
                              onChanged: (v) {
                                ref
                                    .read(sessionFilterParametersNotifierProvider
                                        .notifier)
                                    .updateKeyword(
                                        v.trim().isEmpty ? null : v.trim());
                              },
                            ),
                            const Gap(12),
                            if (pagingData.items.isEmpty)
                              SizedBox(
                                height: constraints.maxHeight - 150,
                                child: Center(
                                  child: EmptyView(
                                    icon: isFilterActive
                                        ? Icons.search_off
                                        : Icons.inbox,
                                    message: isFilterActive
                                        ? context.l10n
                                            .sessions_page__no_filtered_data
                                        : context
                                            .l10n.sessions_page__have_no_data,
                                  ),
                                ),
                              )
                            else ...[
                              _SessionMonthGroupList(
                                sessions: pagingData.items,
                                onSessionTap: (session) {
                                  if (session.teamId != null) {
                                    Navigator.of(context).pushNamed(
                                        HomeRouter.sessionDetailsPage,
                                        arguments: {
                                          'teamId': session.teamId,
                                          'sessionId': session.id,
                                          'session': session,
                                        });
                                  }
                                },
                              ),
                              if (endItemView != null) endItemView,
                            ],
                          ],
                        ),
                      );
                    },
                  );
                },
              ),
              Align(
                alignment: Alignment.bottomCenter,
                child: Padding(
                  padding: const EdgeInsets.only(right: 88, bottom: 16),
                  child: const TutorialVideoContainer(),
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        backgroundColor: canAddSession
            ? null
            : context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
        onPressed: canAddSession
            ? () async {
                if (shouldValidatePlayers) {
                  try {
                    final players = await ref.read(allPlayersProvider.future);
                    if (!context.mounted) return;
                    if (players.isEmpty) {
                      context.showErrorSnackBar(
                        context.l10n.sessions_page__player_required_warning,
                      );
                      return;
                    }
                  } catch (error) {
                    if (!context.mounted) return;
                    final message = error is Failure
                        ? error.translate(context.l10n)
                        : error.toString();
                    context.showErrorSnackBar(message);
                    return;
                  }
                }

                if (!context.mounted) return;
                Navigator.of(context).pushNamed(HomeRouter.addSessionPage);
              }
            : null,
        child: Icon(Icons.add_circle_outline),
      ),
    );
  }
}

class _SessionMonthGroupList extends StatelessWidget {
  const _SessionMonthGroupList({
    required this.sessions,
    required this.onSessionTap,
  });

  final List<Session> sessions;
  final void Function(Session session) onSessionTap;

  @override
  Widget build(BuildContext context) {
    // Group sessions by month
    final groupedSessions = sessions
        .sorted((a, b) => b.createdAt!.compareTo(a.createdAt!))
        .groupListsBy((element) => DateTime(
              element.createdAt!.toLocal().year,
              element.createdAt!.toLocal().month,
            ))
        .entries
        .toList();

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: groupedSessions
          .map((e) {
            final dateTime = e.key;
            final sessionList = e.value;
            return [
              Text(
                dateTimeToString(
                  template: context.l10n.month_format,
                  locale: Localizations.localeOf(context).languageCode,
                  timestamp: dateTime,
                ).toUpperCase(),
                style: TextStyle(
                  fontSize: FontSize.s14,
                  fontWeight: FontWeight.w500,
                  color: context.isDarkMode
                      ? ColorManager.darkSecondaryText
                      : ColorManager.secondaryText,
                  height: 1.7,
                ),
              ),
              const Gap(12),
              ...sessionList.map((session) {
                return Padding(
                  padding: const EdgeInsets.only(bottom: 12),
                  child: SessionCard(
                    session: session,
                    onSessionTap: () => onSessionTap(session),
                  ),
                );
              }),
            ];
          })
          .expand((x) => x)
          .toList(),
    );
  }
}

