/// {@category DTO}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

part 'player_search_request.freezed.dart';
part 'player_search_request.g.dart';

@freezed
abstract class PlayerSearchRequest with _$PlayerSearchRequest {
  @JsonSerializable(explicitToJson: true, fieldRename: FieldRename.none)
  const factory PlayerSearchRequest({
    String? keyword,
    bool? isKeywordUsedAsFuzzySearch,
    @JsonKey(includeIfNull: false) int? page,
    @JsonKey(includeIfNull: false) int? pageSize,
    @JsonKey(includeIfNull: false) PlayerSearchRequestOrderBy? orderBy,
    @JsonKey(includeIfNull: false) bool? isOrderDesc,
  }) = _PlayerSearchRequest;

  factory PlayerSearchRequest.fromJson(Map<String, dynamic> json) =>
      _$PlayerSearchRequestFromJson(json);
}

@JsonEnum(fieldRename: FieldRename.snake)
enum PlayerSearchRequestOrderBy {
  id,
  name,
}

