    19→part 'player_list_controller.g.dart';
    20→
    21→/// A controller class that manages [Player] list.
    22→///
    23→/// This controller refreshes itself when
    24→/// - [repositoryProvider] updated.
    25→/// - [loginStateControllerProvider] updated.
    26→///
    27→/// Note: This controller just handles abstract repository.
    28→/// This means that the controller does not care
    29→/// the implementation of its reporisory is either remote DB or local cache.
    30→/// Therefore do not use anything related to a specific implementation of repository
    31→/// (e.g., the login state of the remote DB).
    32→@Riverpod(keepAlive: true)
    33→class PlayerListController extends _$PlayerListController
    34→    with PagePagingNotifierMixin<Player> {
    35→  static const _playerInitialPageSize = PagePagingNotifierMixin.defaultPageSize;
    36→  static const _ensureAllPlayersPageSize = 10000;
    37→
    38→  @override
    39→  Future<PagingData<Player>> build() {
    40→    ref.watch(loginStateControllerProvider);
    41→    ref.watch(repositoryProvider);
    42→    ref.watch(userAccessibleContentsControllerProvider);
    43→    ref.onDispose(() {
    44→      // NOTE: Slightly delay the timing because manipulating the provider in
    45→      // onDispose causes unexpected behavior.
    46→      Future.microtask(() {
    47→        ref.invalidate(sessionListControllerProvider);
    48→      });
    49→    });
    50→
    51→    return fetch(
    52→      page: PagePagingNotifierMixin.initialPage,
    53→      pageSize: _playerInitialPageSize,
    54→    );
    55→  }
    56→
    57→  @override
    58→  Future<PagingData<Player>> fetch({
    59→    required int page,
    60→    required int pageSize,
    61→  }) async {
    62→    final res = await ref.read(repositoryProvider).getPlayers(
    63→          page: page,
    64→          pageSize: pageSize,
    65→        );
    66→
    67→    if (res.hasRight) {
    68→      final response = res.right;
    69→      return PagingData<Player>(
    70→        items: response.players,
    71→        page: page,
    72→        pageSize: pageSize,
    73→        total: response.total,
    74→        hasMore: response.players.length + page * pageSize < response.total,
    75→      );
    76→    } else {
    77→      // Throw an exception to handle it as an error of AsyncNotifier
    78→      throw res.left;
    79→    }
    80→  }
    81→
    82→  /// Ensure that all player pages are loaded into the current state.
    83→  Future<PagingData<Player>> ensureAllPlayersLoaded({
    84→    int? batchSize,
    85→  }) async {
    86→    final resolvedPageSize = batchSize ?? _ensureAllPlayersPageSize;
    87→
    88→    if (state.isLoading || state.value == null) {
    89→      final initial = await ref.read(playerListControllerProvider.future);
    90→      return _drainRemainingPages(initial, resolvedPageSize);
    91→    }
    92→
    93→    final current = state.value!;
    94→    return _drainRemainingPages(current, resolvedPageSize);
    95→  }
    96→
    97→  Future<PagingData<Player>> _drainRemainingPages(
    98→    PagingData<Player> current,
    99→    int pageSize,
   100→  ) async {
   101→    var latest = current;
   102→
   103→    while (!state.hasError && latest.hasMore) {
   104→      await loadNext(pageSize: pageSize);
   105→
   106→      if (state.hasError) {
   107→        throw state.error ?? StateError('Failed to load players');
   108→      }
   109→
   110→      final next = state.value;
   111→      if (next == null || next.items.length == latest.items.length) {
   112→        break;
   113→      }
   114→      latest = next;
   115→    }
   116→
   117→    if (state.hasError) {
   118→      throw state.error ?? StateError('Failed to load players');
   119→    }
   120→
   121→    return latest;
   122→  }
   123→
   124→  /// Update a [Player] model in the repository.
   125→  Future<Result<Failure, void>> updatePlayer({
   126→    required String playerId,
   127→    required String name,
   128→    required String note,
   129→    required Handedness pitchingHand,
   130→    required Handedness hittingHand,
   131→    String? imageFilePath,
   132→    DateTime? birthday,
   133→  }) async {
   134→    String? imageUrl;
   135→    if (imageFilePath != null) {
   136→      final res = await ref.read(repositoryProvider).uploadPlayerImage(
   137→            playerId: playerId,
   138→            filePath: imageFilePath,
   139→          );
   140→      checkResultForMaintenance(ref, res);
   141→      if (!res.hasRight) {
   142→        return res;
   143→      }
   144→      imageUrl = res.right;
   145→    }
   146→
   147→    final res = await ref.read(repositoryProvider).editPlayer(
   148→          playerId: playerId,
   149→          name: name,
   150→          note: note,
   151→          imageUrl: imageUrl,
   152→          pitchingHand: pitchingHand,
   153→          hittingHand: hittingHand,
