part 'player_list_controller.g.dart';

/// A controller class that manages [Player] list.
///
/// This controller refreshes itself when
/// - [repositoryProvider] updated.
/// - [loginStateControllerProvider] updated.
///
/// Note: This controller just handles abstract repository.
/// This means that the controller does not care
/// the implementation of its reporisory is either remote DB or local cache.
/// Therefore do not use anything related to a specific implementation of repository
/// (e.g., the login state of the remote DB).
@Riverpod(keepAlive: true)
class PlayerListController extends _$PlayerListController
    with PagePagingNotifierMixin<Player> {
  static const _playerInitialPageSize = PagePagingNotifierMixin.defaultPageSize;
  static const _ensureAllPlayersPageSize = 10000;

  @override
  Future<PagingData<Player>> build() {
    ref.watch(loginStateControllerProvider);
    ref.watch(repositoryProvider);
    ref.watch(userAccessibleContentsControllerProvider);
    ref.onDispose(() {
      // NOTE: Slightly delay the timing because manipulating the provider in
      // onDispose causes unexpected behavior.
      Future.microtask(() {
        ref.invalidate(sessionListControllerProvider);
      });
    });

    return fetch(
      page: PagePagingNotifierMixin.initialPage,
      pageSize: _playerInitialPageSize,
    );
  }

  @override
  Future<PagingData<Player>> fetch({
    required int page,
    required int pageSize,
  }) async {
    final res = await ref.read(repositoryProvider).getPlayers(
          page: page,
          pageSize: pageSize,
        );

    if (res.hasRight) {
      final response = res.right;
      return PagingData<Player>(
        items: response.players,
        page: page,
        pageSize: pageSize,
        total: response.total,
        hasMore: response.players.length + page * pageSize < response.total,
      );
    } else {
      // Throw an exception to handle it as an error of AsyncNotifier
      throw res.left;
    }
  }

  /// Ensure that all player pages are loaded into the current state.
  Future<PagingData<Player>> ensureAllPlayersLoaded({
    int? batchSize,
  }) async {
    final resolvedPageSize = batchSize ?? _ensureAllPlayersPageSize;

    if (state.isLoading || state.value == null) {
      final initial = await ref.read(playerListControllerProvider.future);
      return _drainRemainingPages(initial, resolvedPageSize);
    }

    final current = state.value!;
    return _drainRemainingPages(current, resolvedPageSize);
  }

  Future<PagingData<Player>> _drainRemainingPages(
    PagingData<Player> current,
    int pageSize,
  ) async {
    var latest = current;

    while (!state.hasError && latest.hasMore) {
      await loadNext(pageSize: pageSize);

      if (state.hasError) {
        throw state.error ?? StateError('Failed to load players');
      }

      final next = state.value;
      if (next == null || next.items.length == latest.items.length) {
        break;
      }
      latest = next;
    }

    if (state.hasError) {
      throw state.error ?? StateError('Failed to load players');
    }

    return latest;
  }

  /// Update a [Player] model in the repository.
  Future<Result<Failure, void>> updatePlayer({
    required String playerId,
    required String name,
    required String note,
    required Handedness pitchingHand,
    required Handedness hittingHand,
    String? imageFilePath,
    DateTime? birthday,
  }) async {
    String? imageUrl;
    if (imageFilePath != null) {
      final res = await ref.read(repositoryProvider).uploadPlayerImage(
            playerId: playerId,
            filePath: imageFilePath,
          );
      checkResultForMaintenance(ref, res);
      if (!res.hasRight) {
        return res;
      }
      imageUrl = res.right;
    }

    final res = await ref.read(repositoryProvider).editPlayer(
          playerId: playerId,
          name: name,
          note: note,
          imageUrl: imageUrl,
          pitchingHand: pitchingHand,
          hittingHand: hittingHand,
          birthday: birthday,
        );

    if (!res.hasRight) {
      return res;
    }

    // Reflect the update result to the state
    if (state.value != null) {
      final updatedPlayer = res.right.player;
      final current = state.value!;
      final newItems = current.items
          .map((p) => p.id == updatedPlayer.id ? updatedPlayer : p)
          .toList();
      state = AsyncData(current.copyWith(items: newItems));
    }

    // Update the controller that uses the Player information
    ref.invalidate(sessionListControllerProvider);
    return res;
  }

  /// Delete a [Player] model from the repository.
  Future<Result<Failure, void>> deletePlayer(String playerId) async {
    final res =
        await ref.read(repositoryProvider).deletePlayer(playerId: playerId);
    checkResultForMaintenance(ref, res);
    if (!res.hasRight) return res;

    // Reflect the delete result to the state
    if (state.value != null) {
      final current = state.value!;
      final newItems = current.items.where((p) => p.id != playerId).toList();
      state = AsyncData(current.copyWith(items: newItems));
    }

    return res;
  }

  /// Create a [Player] model in the repository.
  Future<Result<Failure, PlayerCreateResponse>> createPlayer({
    required String playerName,
    required String note,
    required Handedness pitchingHand,
    required Handedness hittingHand,
    String? imageFilePath,
    DateTime? birthday,
  }) async {
    final res = await ref.read(repositoryProvider).addPlayer(
          playerName: playerName,
          note: note,
          pitchingHand: pitchingHand,
          hittingHand: hittingHand,
          birthday: birthday,
        );
    checkResultForMaintenance(ref, res);
    if (!res.hasRight) return res;

    // The case that the image is uploaded.
    if (imageFilePath != null) {
      final playerId = res.right.player.id;
      if (playerId == null) return res;

      final res2 = await ref.read(repositoryProvider).uploadPlayerImage(
            playerId: playerId,
            filePath: imageFilePath,
          );

      if (!res2.hasRight) return Both(res2.left, res.right);

      final imageUrl = res2.right;

      final res3 = await ref.read(repositoryProvider).editPlayer(
            playerId: playerId,
            name: playerName,
            note: note,
            pitchingHand: pitchingHand,
            hittingHand: hittingHand,
            imageUrl: imageUrl,
            birthday: birthday,
          );

      if (!res3.hasRight) return Both(res3.left, res.right);

      // Reflect the update result to the state
      if (state.value != null) {
        final updatedPlayer = res3.right.player;
        final current = state.value!;
        final newItems = [...current.items, updatedPlayer];
        state = AsyncData(current.copyWith(items: newItems));
      }
    } else {
      // The case that the image is not uploaded.
      if (state.value != null) {
        final updatedPlayer = res.right.player;
        final current = state.value!;
        final newItems = [...current.items, updatedPlayer];
        state = AsyncData(current.copyWith(items: newItems));
      }
    }

    return res;
  }
}

@Riverpod(keepAlive: true)
Future<List<Player>> allPlayers(Ref ref) async {
  // Use ref.read instead of ref.watch to avoid circular dependency
  // when called from within other provider methods
  final notifier = ref.read(playerListControllerProvider.notifier);
  final pagingData = await notifier.ensureAllPlayersLoaded();
  return pagingData.items;
}

