import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';

class PlayerSearchBarWithFilter extends HookConsumerWidget {
  final String word;
  final ValueChanged<String> onChanged;
  const PlayerSearchBarWithFilter({
    super.key,
    required this.word,
    required this.onChanged,
  });

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final controller = useTextEditingController(text: word);
    final focusNode = useFocusNode();

    useEffect(() {
      if (controller.text != word) controller.text = word;
      return null;
    }, [word]);

    return TextField(
      controller: controller,
      focusNode: focusNode,
      decoration: InputDecoration(
        prefixIcon: Icon(Icons.search),
        hintText: context.l10n.sessions_page__filter_hint,
        isDense: true,
        border: OutlineInputBorder(borderRadius: BorderRadius.circular(12)),
        suffixIcon: controller.text.isNotEmpty
            ? IconButton(
                icon: Icon(Icons.clear),
                onPressed: () {
                  controller.clear();
                  onChanged('');
                },
              )
            : null,
      ),
      onChanged: onChanged,
      textInputAction: TextInputAction.search,
    );
  }
}

