library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/views/components/empty_view.dart';
import 'package:baseball_detector_flutter/views/components/paging_helper.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/players/components/player_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/players/components/player_search_bar_with_filter.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// A page widget class to manage player lists.
class PlayersPage extends HookConsumerWidget {
  const PlayersPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamId = ref.watch(profileStorageProvider).getTeamId()!;
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final canAddPlayer = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.basic,
          RoleLevel.write,
          false,
        ) ??
        false;

    final keyword = ref.watch(playerSearchKeywordNotifierProvider);

    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: Column(
            children: [
              // Search bar
              Padding(
                padding: const EdgeInsets.only(bottom: 12),
                child: PlayerSearchBarWithFilter(
                  word: keyword ?? '',
                  onSubmitted: (word) {
                    ref
                        .read(playerSearchKeywordNotifierProvider.notifier)
                        .updateKeyword(
                            word.trim().isEmpty ? null : word.trim());
                  },
                ),
              ),
              // Player list
              Expanded(
                child: PagingHelper<PlayerListController, Player>(
                  provider: playerListControllerProvider,
                  contentBuilder:
                      (PagingData<Player> data, Widget? endItemView) {
                    if (data.items.isEmpty) {
                      return EmptyView(
                        icon: Icons.people_outline,
                        message: keyword != null && keyword.isNotEmpty
                            ? context.l10n.common__no_data
                            : context.l10n.players_page__have_no_data,
                        height: context.screenHeight * 0.8,
                      );
                    }
                    return ListView(
                      children: [
                        ...data.items
                            .map((player) => PlayerCard(player: player)),
                        if (endItemView != null) endItemView else const Gap(80),
                      ],
                    );
                  },
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        backgroundColor: canAddPlayer
            ? null
            : context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
        onPressed: canAddPlayer
            ? () {
                Navigator.of(context).pushNamed(HomeRouter.createPlayerPage);
              }
            : null,
        child: Icon(Icons.person_add_alt),
      ),
    );
  }
}
